sql:
SELECT first_name, last_name, height, weight, hometown, high_school
FROM wrestlers
WHERE height > '6ft' AND weight >= 150;

SELECT COUNT(match_video_id)
FROM match_videos
WHERE match_id >= 1;

SELECT first_name, last_name 
FROM wrestlers 
WHERE wrestler_id = 0;

external_knowledge:
- "treasure maps" metaphorically refers to the video URLs that provide access to the match videos;
- "victorious lands" symbolically represents the matches where the team won;
- "report whisperers" and "sang the song of triumph" are poetic expressions for the match reports and the text content "We won this match...".;

sql:
SELECT match_video_id, video_url
FROM match_videos
WHERE video_url LIKE '%example.com%';

external_knowledge:
- "taller than 60 inches" refers to the height criteria CAST(SUBSTR(w.height, -2) AS INTEGER) > 60;
- "redshirted" indicates wrestlers who are in their redshirt year (w.redshirt = 1);
- "champions" refers to wrestlers who are ranked first (rk.rank = '1st');
- "emerged victorious" implies having at least one win (r.wins >= 1);
- "hidden from the spotlight" metaphorically refers to the redshirt status of the wrestlers.

sql:
SELECT report_text
FROM match_reports
WHERE match_id = 'Match ID';

external_knowledge:
- 'titans' metaphorically refers to the strong wrestlers in the database;
- 'heavy enough to crush the weak' corresponds to having a weight greater than 150 pounds;
- 'not in a state of dormancy' indicates that they are not on redshirt status, implying they are actively competing;
- 'battleground of competition' metaphorically refers to the environment where wrestlers compete, and thus they are part of active competition;
- 'revealing their towering heights, commanding weights' refers to the wrestler's height and weight;
- 'the institutions that forged them' refers to the schools where these wrestlers are affiliated.

sql:
SELECT matches.match_date, match_videos.video_url
FROM matches
JOIN match_videos ON matches.match_id = match_videos.match_id;

SELECT first_name, last_name 
FROM wrestlers 
WHERE weight > 120;
